-- {"operators": "INNER_JOIN,AGGREGATE,WINDOW", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "ITEM,STOCK", "ducklake": true}
SELECT s.S_W_ID, s.S_I_ID, s.S_QUANTITY, AVG(s.S_QUANTITY) OVER (PARTITION BY s.S_W_ID) AS w_avg, (s.S_QUANTITY - AVG(s.S_QUANTITY) OVER (PARTITION BY s.S_W_ID)) AS diff_from_avg FROM dl.STOCK s JOIN dl.ITEM i ON s.S_I_ID = i.I_ID;
